  // ─── 27. GPP / NPP / RESPIRATION ENERGY FLOW ─────────────────────────────
  static gppNppRespirationEnergyFlowDiagramsvg = `<?xml version="1.0" encoding="utf-8"?>
<svg fill="#000000" version="1.1" id="EnergyFlow" xmlns="http://www.w3.org/2000/svg"
     width="800px" height="800px" viewBox="0 0 480 420" enable-background="new 0 0 480 420" xml:space="preserve">

  <!-- Title -->
  <text x="56" y="20" font-family="Arial" font-size="13" font-weight="bold" fill="#000000">GPP, NPP &amp; Respiration — Ecosystem Energy Flow</text>

  <!-- ── Definitions box ── -->
  <rect x="8" y="34" width="464" height="64" rx="5" fill="none" stroke="#000000" stroke-width="4"/>
  <text x="16" y="52" font-family="Arial" font-size="10" font-weight="bold" fill="#000000">GPP</text>
  <text x="48" y="52" font-family="Arial" font-size="9" fill="#000000">= Gross Primary Productivity — total photosynthesis energy fixed by producers</text>
  <text x="16" y="67" font-family="Arial" font-size="10" font-weight="bold" fill="#000000">NPP</text>
  <text x="48" y="67" font-family="Arial" font-size="9" fill="#000000">= Net Primary Productivity = GPP − Rp (plant respiration) — energy available to consumers</text>
  <text x="16" y="82" font-family="Arial" font-size="10" font-weight="bold" fill="#000000">NCP</text>
  <text x="48" y="82" font-family="Arial" font-size="9" fill="#000000">= Net Community Productivity = GPP − Rtotal (all organisms) — ecosystem C balance</text>

  <!-- ── Energy flow bar diagram ── -->
  <!-- Sunlight input -->
  <text x="6" y="130" font-family="Arial" font-size="10" font-weight="bold" fill="#000000">Sunlight</text>
  <text x="6" y="143" font-family="Arial" font-size="10" font-weight="bold" fill="#000000">Input</text>
  <line x1="80" y1="136" x2="130" y2="136" stroke="#000000" stroke-width="4"/>
  <polygon points="126,132 138,136 126,140" fill="#000000"/>

  <!-- GPP bar -->
  <rect x="138" y="114" width="320" height="44" rx="4" fill="none" stroke="#000000" stroke-width="4.5"/>
  <text x="270" y="138" font-family="Arial" font-size="12" font-weight="bold" fill="#000000">GPP (100%)</text>

  <!-- Split: Rp downward -->
  <line x1="138" y1="158" x2="138" y2="192" stroke="#000000" stroke-width="4"/>
  <polygon points="134,189 138,200 142,189" fill="#000000"/>
  <!-- Rp box -->
  <rect x="82" y="200" width="110" height="30" rx="4" fill="none" stroke="#000000" stroke-width="3.5"/>
  <text x="96" y="217" font-family="Arial" font-size="9.5" font-weight="bold" fill="#000000">Rp (~40–60%)</text>
  <text x="84" y="228" font-family="Arial" font-size="8.5" fill="#000000">Plant respiration</text>
  <!-- Heat released label -->
  <line x1="138" y1="230" x2="138" y2="258" stroke="#000000" stroke-width="2.5" stroke-dasharray="4,3"/>
  <polygon points="134,255 138,266 142,255" fill="#000000"/>
  <text x="80" y="278" font-family="Arial" font-size="8.5" fill="#000000">Heat lost to environment</text>

  <!-- NPP bar (shorter) -->
  <rect x="210" y="200" width="248" height="40" rx="4" fill="none" stroke="#000000" stroke-width="4.5"/>
  <text x="284" y="225" font-family="Arial" font-size="12" font-weight="bold" fill="#000000">NPP (~50%)</text>
  <text x="220" y="240" font-family="Arial" font-size="8.5" fill="#000000">Available to consumers</text>

  <!-- NPP splits: herbivore consumption vs. litter/decomposers -->
  <!-- Herbivore -->
  <line x1="260" y1="240" x2="260" y2="276" stroke="#000000" stroke-width="3.5"/>
  <polygon points="256,273 260,284 264,273" fill="#000000"/>
  <rect x="192" y="284" width="136" height="28" rx="4" fill="none" stroke="#000000" stroke-width="3.5"/>
  <text x="204" y="298" font-family="Arial" font-size="9" font-weight="bold" fill="#000000">Herbivore consumption</text>
  <text x="210" y="310" font-family="Arial" font-size="8" fill="#000000">→ secondary production</text>

  <!-- Herbivore → respiration + secondary consumers -->
  <line x1="260" y1="312" x2="260" y2="346" stroke="#000000" stroke-width="3.5"/>
  <polygon points="256,343 260,354 264,343" fill="#000000"/>
  <rect x="196" y="354" width="128" height="28" rx="4" fill="none" stroke="#000000" stroke-width="3"/>
  <text x="210" y="369" font-family="Arial" font-size="9" font-weight="bold" fill="#000000">Secondary production</text>
  <text x="216" y="381" font-family="Arial" font-size="8" fill="#000000">→ higher trophic levels</text>

  <!-- Litter / detritus pathway -->
  <line x1="400" y1="240" x2="400" y2="284" stroke="#000000" stroke-width="3.5"/>
  <polygon points="396,281 400,292 404,281" fill="#000000"/>
  <rect x="342" y="292" width="116" height="28" rx="4" fill="none" stroke="#000000" stroke-width="3.5"/>
  <text x="356" y="306" font-family="Arial" font-size="9" font-weight="bold" fill="#000000">Litter / Detritus</text>
  <text x="350" y="318" font-family="Arial" font-size="8" fill="#000000">→ Decomposers (Rd)</text>

  <!-- Rd → CO2 -->
  <line x1="400" y1="320" x2="400" y2="354" stroke="#000000" stroke-width="3.5"/>
  <polygon points="396,351 400,362 404,351" fill="#000000"/>
  <rect x="342" y="362" width="116" height="28" rx="4" fill="none" stroke="#000000" stroke-width="3"/>
  <text x="358" y="376" font-family="Arial" font-size="9" font-weight="bold" fill="#000000">CO₂ → atmosphere</text>
  <text x="354" y="388" font-family="Arial" font-size="8" fill="#000000">Carbon returned</text>

  <!-- Formula summary -->
  <rect x="8" y="360" width="180" height="52" rx="4" fill="none" stroke="#000000" stroke-width="3" stroke-dasharray="5,3"/>
  <text x="16" y="376" font-family="Arial" font-size="9" font-weight="bold" fill="#000000">Key equations:</text>
  <text x="16" y="390" font-family="Arial" font-size="8.5" fill="#000000">NPP = GPP − Rp</text>
  <text x="16" y="402" font-family="Arial" font-size="8.5" fill="#000000">NCP = GPP − (Rp + Rc + Rd)</text>
</svg>`;

