  // ─── 19. ANTIGEN PRESENTATION & T/B CELL ACTIVATION ──────────────────────
  static antigenPresentationToTAndBCellActivationPathwayDiagramsvg = `<?xml version="1.0" encoding="utf-8"?>
<svg fill="#000000" version="1.1" id="AgPresentation" xmlns="http://www.w3.org/2000/svg"
     width="800px" height="800px" viewBox="0 0 520 560" enable-background="new 0 0 520 560" xml:space="preserve">

  <!-- Title -->
  <text x="30" y="22" font-family="Arial" font-size="13" font-weight="bold" fill="#000000">Antigen Presentation &amp; T/B Cell Activation Pathway</text>

  <!-- ── APC (Dendritic cell / Macrophage) ── -->
  <ellipse cx="260" cy="112" rx="80" ry="52" fill="none" stroke="#000000" stroke-width="6"/>
  <!-- Dendritic projections -->
  <line x1="180" y1="98" x2="154" y2="76" stroke="#000000" stroke-width="3.5"/>
  <line x1="184" y1="82" x2="162" y2="60" stroke="#000000" stroke-width="3.5"/>
  <line x1="196" y1="68" x2="178" y2="46" stroke="#000000" stroke-width="3.5"/>
  <line x1="340" y1="98" x2="366" y2="76" stroke="#000000" stroke-width="3.5"/>
  <line x1="336" y1="82" x2="358" y2="60" stroke="#000000" stroke-width="3.5"/>
  <line x1="324" y1="68" x2="342" y2="46" stroke="#000000" stroke-width="3.5"/>
  <text x="202" y="106" font-family="Arial" font-size="10" font-weight="bold" fill="#000000">APC / DC</text>
  <!-- MHC II on surface -->
  <rect x="226" y="158" width="68" height="18" rx="4" fill="none" stroke="#000000" stroke-width="3"/>
  <text x="232" y="171" font-family="Arial" font-size="8.5" font-weight="bold" fill="#000000">MHC II + peptide</text>
  <!-- MHC I on surface -->
  <rect x="195" y="130" width="130" height="14" rx="3" fill="none" stroke="#000000" stroke-width="2.5" stroke-dasharray="5,3"/>
  <text x="200" y="141" font-family="Arial" font-size="7.5" fill="#000000">MHC I (all nucleated cells)</text>

  <!-- Phagocytosis / antigen uptake arrow (from top) -->
  <line x1="260" y1="34" x2="260" y2="60" stroke="#000000" stroke-width="3.5" stroke-dasharray="5,3"/>
  <polygon points="256,57 260,68 264,57" fill="#000000"/>
  <text x="162" y="28" font-family="Arial" font-size="9" font-weight="bold" fill="#000000">Pathogen/Antigen</text>
  <text x="178" y="38" font-family="Arial" font-size="8" fill="#000000">(phagocytosis / endocytosis)</text>

  <!-- ── Split: CD4 T-cell (left) and CD8 T-cell (right) ── -->
  <!-- Main arrow down from APC -->
  <line x1="220" y1="176" x2="140" y2="224" stroke="#000000" stroke-width="3.5"/>
  <polygon points="137,220 132,232 143,225" fill="#000000"/>
  <line x1="300" y1="176" x2="380" y2="224" stroke="#000000" stroke-width="3.5"/>
  <polygon points="377,220 383,232 389,223" fill="#000000"/>

  <!-- CD4+ T-helper cell (left) -->
  <ellipse cx="116" cy="258" rx="62" ry="36" fill="none" stroke="#000000" stroke-width="5"/>
  <text x="76" y="252" font-family="Arial" font-size="9" font-weight="bold" fill="#000000">CD4⁺ T-helper</text>
  <text x="80" y="264" font-family="Arial" font-size="8.5" fill="#000000">TCR binds MHC II</text>
  <text x="80" y="275" font-family="Arial" font-size="8" fill="#000000">CD28–B7 costimulation</text>

  <!-- CD8+ Cytotoxic T cell (right) -->
  <ellipse cx="404" cy="258" rx="62" ry="36" fill="none" stroke="#000000" stroke-width="5"/>
  <text x="364" y="252" font-family="Arial" font-size="9" font-weight="bold" fill="#000000">CD8⁺ CTL</text>
  <text x="360" y="264" font-family="Arial" font-size="8.5" fill="#000000">TCR binds MHC I</text>
  <text x="360" y="275" font-family="Arial" font-size="8" fill="#000000">Cross-presentation</text>

  <!-- CD4 activation arrow + cytokines -->
  <line x1="116" y1="294" x2="116" y2="338" stroke="#000000" stroke-width="4"/>
  <polygon points="112,335 116,346 120,335" fill="#000000"/>

  <!-- Th subsets box -->
  <rect x="20" y="346" width="192" height="80" rx="6" fill="none" stroke="#000000" stroke-width="3.5"/>
  <text x="70" y="360" font-family="Arial" font-size="9" font-weight="bold" fill="#000000">T-helper Subsets</text>
  <text x="28" y="374" font-family="Arial" font-size="8.5" fill="#000000">Th1 → IFN-γ (macrophage act.)</text>
  <text x="28" y="386" font-family="Arial" font-size="8.5" fill="#000000">Th2 → IL-4/5 (B cell help)</text>
  <text x="28" y="398" font-family="Arial" font-size="8.5" fill="#000000">Th17 → IL-17 (neutrophil)</text>
  <text x="28" y="410" font-family="Arial" font-size="8.5" fill="#000000">Treg → IL-10/TGF-β (suppression)</text>
  <text x="28" y="422" font-family="Arial" font-size="8.5" fill="#000000">Tfh → germinal centre B cell help</text>

  <!-- CD4 → B cell help arrow -->
  <line x1="190" y1="396" x2="240" y2="396" stroke="#000000" stroke-width="3.5"/>
  <polygon points="237,392 248,396 237,400" fill="#000000"/>

  <!-- B cell activation -->
  <ellipse cx="295" cy="396" rx="50" ry="36" fill="none" stroke="#000000" stroke-width="5"/>
  <text x="263" y="390" font-family="Arial" font-size="9" font-weight="bold" fill="#000000">B Cell</text>
  <text x="256" y="402" font-family="Arial" font-size="8.5" fill="#000000">BCR + antigen</text>
  <text x="256" y="414" font-family="Arial" font-size="8.5" fill="#000000">CD40–CD40L</text>

  <!-- B cell → Plasma cell -->
  <line x1="295" y1="432" x2="295" y2="464" stroke="#000000" stroke-width="4"/>
  <polygon points="291,461 295,472 299,461" fill="#000000"/>
  <rect x="234" y="472" width="122" height="32" rx="5" fill="none" stroke="#000000" stroke-width="4"/>
  <text x="258" y="486" font-family="Arial" font-size="9" font-weight="bold" fill="#000000">Plasma Cell</text>
  <text x="244" y="497" font-family="Arial" font-size="8.5" fill="#000000">→ antibody secretion</text>

  <!-- B cell → Memory B cell -->
  <line x1="344" y1="408" x2="400" y2="420" stroke="#000000" stroke-width="3.5" stroke-dasharray="5,3"/>
  <polygon points="396,417 407,422 400,431" fill="#000000"/>
  <rect x="400" y="408" width="100" height="32" rx="5" fill="none" stroke="#000000" stroke-width="3"/>
  <text x="410" y="422" font-family="Arial" font-size="9" font-weight="bold" fill="#000000">Memory B</text>
  <text x="406" y="432" font-family="Arial" font-size="8" fill="#000000">Long-lived; rapid 2°</text>

  <!-- CD8 → kill cell -->
  <line x1="404" y1="294" x2="404" y2="338" stroke="#000000" stroke-width="4"/>
  <polygon points="400,335 404,346 408,335" fill="#000000"/>
  <rect x="338" y="346" width="132" height="56" rx="5" fill="none" stroke="#000000" stroke-width="4"/>
  <text x="372" y="362" font-family="Arial" font-size="9" font-weight="bold" fill="#000000">Cytotoxicity</text>
  <text x="344" y="374" font-family="Arial" font-size="8.5" fill="#000000">Perforin / Granzyme B</text>
  <text x="344" y="386" font-family="Arial" font-size="8.5" fill="#000000">FasL → apoptosis</text>
  <text x="344" y="398" font-family="Arial" font-size="8.5" fill="#000000">Kills infected / tumour cells</text>

  <!-- Memory T cells note -->
  <line x1="116" y1="426" x2="44" y2="460" stroke="#000000" stroke-width="3" stroke-dasharray="5,3"/>
  <rect x="6" y="454" width="86" height="32" rx="4" fill="none" stroke="#000000" stroke-width="2.5" stroke-dasharray="4,2"/>
  <text x="10" y="468" font-family="Arial" font-size="8.5" font-weight="bold" fill="#000000">Memory T</text>
  <text x="10" y="479" font-family="Arial" font-size="8" fill="#000000">CD4 + CD8 Tmem</text>

  <!-- IL-2 autocrine expansion label -->
  <path d="M58,258 C28,240 20,210 58,218 C72,222 92,238 116,258"
        fill="none" stroke="#000000" stroke-width="2.5" stroke-dasharray="5,3"/>
  <text x="10" y="232" font-family="Arial" font-size="8" fill="#000000">IL-2 clonal</text>
  <text x="14" y="243" font-family="Arial" font-size="8" fill="#000000">expansion</text>

  <text x="10" y="530" font-family="Arial" font-size="8.5" fill="#000000">MHC II → CD4 Th cells; MHC I → CD8 CTLs. Costimulation required to prevent anergy.</text>
  <text x="10" y="542" font-family="Arial" font-size="8.5" fill="#000000">Tfh cells provide cognate B cell help in germinal centres for affinity maturation.</text>
</svg>`;

