  // ─── MYOSIN ATPASE CROSSBRIDGE POWER STROKE CYCLE ────────────────────────
  static myosinAtpaseCrossbridge_powerStrokeCycleActinFilamentDiagramsvg = `<?xml version="1.0" encoding="utf-8"?>
<svg fill="#000000" version="1.1" xmlns="http://www.w3.org/2000/svg"
     width="800px" height="800px" viewBox="0 0 480 360" enable-background="new 0 0 480 360" xml:space="preserve">
  <text x="80" y="20" font-family="Arial" font-size="13" font-weight="bold" fill="#000000">Myosin ATPase Cross-Bridge Power Stroke Cycle</text>

  <!-- Actin filament top -->
  <rect x="20" y="46" width="440" height="22" rx="11" fill="none" stroke="#000000" stroke-width="5"/>
  <text x="8" y="42" font-family="Arial" font-size="10" font-weight="bold" fill="#000000">Actin filament</text>
  <!-- Actin monomers (circles along filament) -->
  <circle cx="55"  cy="57" r="9" fill="none" stroke="#000000" stroke-width="3"/>
  <circle cx="90"  cy="57" r="9" fill="none" stroke="#000000" stroke-width="3"/>
  <circle cx="125" cy="57" r="9" fill="none" stroke="#000000" stroke-width="3"/>
  <circle cx="160" cy="57" r="9" fill="none" stroke="#000000" stroke-width="3"/>
  <circle cx="195" cy="57" r="9" fill="none" stroke="#000000" stroke-width="3"/>
  <circle cx="230" cy="57" r="9" fill="none" stroke="#000000" stroke-width="3"/>
  <circle cx="265" cy="57" r="9" fill="none" stroke="#000000" stroke-width="3"/>
  <circle cx="300" cy="57" r="9" fill="none" stroke="#000000" stroke-width="3"/>
  <circle cx="335" cy="57" r="9" fill="none" stroke="#000000" stroke-width="3"/>
  <circle cx="370" cy="57" r="9" fill="none" stroke="#000000" stroke-width="3"/>
  <circle cx="405" cy="57" r="9" fill="none" stroke="#000000" stroke-width="3"/>
  <circle cx="440" cy="57" r="9" fill="none" stroke="#000000" stroke-width="3"/>

  <!-- Four-state cycle boxes -->
  <!-- State 1: Rigor (top-left) -->
  <rect x="20" y="100" width="190" height="70" rx="6" fill="none" stroke="#000000" stroke-width="4"/>
  <text x="28" y="118" font-family="Arial" font-size="10" font-weight="bold" fill="#000000">State 1: Rigor (Attached)</text>
  <text x="28" y="132" font-family="Arial" font-size="9" fill="#000000">Myosin head tightly bound</text>
  <text x="28" y="145" font-family="Arial" font-size="9" fill="#000000">to actin. No nucleotide.</text>
  <text x="28" y="158" font-family="Arial" font-size="9" fill="#000000">Low-energy conformation.</text>
  <!-- Myosin head diagram state 1 -->
  <path d="M90,100 L90,80 Q90,68 100,68 L160,68" fill="none" stroke="#000000" stroke-width="4" stroke-linecap="round"/>
  <ellipse cx="90" cy="88" rx="10" ry="12" fill="none" stroke="#000000" stroke-width="3"/>

  <!-- State 2: ATP Binding (top-right) -->
  <rect x="270" y="100" width="190" height="70" rx="6" fill="none" stroke="#000000" stroke-width="4"/>
  <text x="278" y="118" font-family="Arial" font-size="10" font-weight="bold" fill="#000000">State 2: ATP Binding</text>
  <text x="278" y="132" font-family="Arial" font-size="9" fill="#000000">ATP binds → head releases</text>
  <text x="278" y="145" font-family="Arial" font-size="9" fill="#000000">from actin (detached).</text>
  <text x="278" y="158" font-family="Arial" font-size="9" fill="#000000">ATP: adenosine-P~P~P</text>
  <!-- Detached head state 2 -->
  <path d="M340,100 L340,85" fill="none" stroke="#000000" stroke-width="4" stroke-linecap="round"/>
  <ellipse cx="340" cy="92" rx="10" ry="8" fill="none" stroke="#000000" stroke-width="3"/>
  <text x="350" y="88" font-family="Arial" font-size="8" fill="#000000">ATP</text>

  <!-- State 3: Cocked (bottom-left) -->
  <rect x="20" y="230" width="190" height="70" rx="6" fill="none" stroke="#000000" stroke-width="4"/>
  <text x="28" y="248" font-family="Arial" font-size="10" font-weight="bold" fill="#000000">State 3: Cocked (High Energy)</text>
  <text x="28" y="262" font-family="Arial" font-size="9" fill="#000000">ATP → ADP + Pi. Head</text>
  <text x="28" y="275" font-family="Arial" font-size="9" fill="#000000">swings to 90° (cocked).</text>
  <text x="28" y="288" font-family="Arial" font-size="9" fill="#000000">Weakly reattaches to actin.</text>

  <!-- State 4: Power Stroke (bottom-right) -->
  <rect x="270" y="230" width="190" height="70" rx="6" fill="none" stroke="#000000" stroke-width="4"/>
  <text x="278" y="248" font-family="Arial" font-size="10" font-weight="bold" fill="#000000">State 4: Power Stroke</text>
  <text x="278" y="262" font-family="Arial" font-size="9" fill="#000000">Pi released → head swings</text>
  <text x="278" y="275" font-family="Arial" font-size="9" fill="#000000">to 45°. ADP released.</text>
  <text x="278" y="288" font-family="Arial" font-size="9" fill="#000000">Actin slides ~10 nm.</text>

  <!-- Cycle arrows between states -->
  <!-- 1→2 top arrow right -->
  <line x1="210" y1="135" x2="270" y2="135" stroke="#000000" stroke-width="3.5"/>
  <polygon points="266,131 276,135 266,139" fill="#000000"/>
  <text x="222" y="128" font-family="Arial" font-size="8.5" fill="#000000">+ ATP</text>

  <!-- 2→4 right arrow down -->
  <line x1="365" y1="170" x2="365" y2="230" stroke="#000000" stroke-width="3.5"/>
  <polygon points="361,226 365,236 369,226" fill="#000000"/>
  <text x="370" y="205" font-family="Arial" font-size="8.5" fill="#000000">Hydrolysis</text>
  <text x="368" y="216" font-family="Arial" font-size="8.5" fill="#000000">→ADP+Pi</text>

  <!-- 4→3 bottom arrow left -->
  <line x1="270" y1="265" x2="210" y2="265" stroke="#000000" stroke-width="3.5"/>
  <polygon points="214,261 204,265 214,269" fill="#000000"/>
  <text x="216" y="258" font-family="Arial" font-size="8.5" fill="#000000">Pi release</text>

  <!-- 3→1 left arrow up -->
  <line x1="115" y1="230" x2="115" y2="170" stroke="#000000" stroke-width="3.5"/>
  <polygon points="111,174 115,164 119,174" fill="#000000"/>
  <text x="38" y="205" font-family="Arial" font-size="8.5" fill="#000000">ADP release</text>
  <text x="32" y="216" font-family="Arial" font-size="8.5" fill="#000000">→ Rigor again</text>

  <!-- Power stroke displacement arrow -->
  <line x1="290" y1="320" x2="380" y2="320" stroke="#000000" stroke-width="4"/>
  <polygon points="376,316 386,320 376,324" fill="#000000"/>
  <text x="280" y="340" font-family="Arial" font-size="9" font-weight="bold" fill="#000000">Net actin displacement ~10 nm per stroke</text>

  <!-- Myosin tail label -->
  <text x="20" y="355" font-family="Arial" font-size="9" fill="#000000">Myosin tail (thick filament backbone) not shown</text>
</svg>`;

  // ─── UCP1 BROWN ADIPOSE THERMOGENESIS ────────────────────────────────────
