  // ─── PFK-1 ALLOSTERIC REGULATION ─────────────────────────────────────────
  static pfk1AllostericRegulationAmpAtpCitrateSignallingDiagramsvg = `<?xml version="1.0" encoding="utf-8"?>
<svg fill="#000000" version="1.1" xmlns="http://www.w3.org/2000/svg"
     width="800px" height="800px" viewBox="0 0 480 400" enable-background="new 0 0 480 400" xml:space="preserve">
  <text x="50" y="18" font-family="Arial" font-size="13" font-weight="bold" fill="#000000">PFK-1 Allosteric Regulation: AMP/ATP/Citrate Signalling</text>

  <!-- PFK-1 enzyme central -->
  <ellipse cx="240" cy="200" rx="90" ry="60" fill="none" stroke="#000000" stroke-width="6"/>
  <text x="198" y="195" font-family="Arial" font-size="12" font-weight="bold" fill="#000000">PFK-1</text>
  <text x="186" y="210" font-family="Arial" font-size="9" fill="#000000">(Phosphofructokinase-1)</text>
  <text x="196" y="222" font-family="Arial" font-size="8.5" fill="#000000">Tetrameric enzyme</text>
  <text x="200" y="234" font-family="Arial" font-size="8.5" fill="#000000">Rate-limiting step</text>

  <!-- Substrates (top) -->
  <rect x="164" y="46" width="152" height="34" rx="6" fill="none" stroke="#000000" stroke-width="4"/>
  <text x="172" y="64" font-family="Arial" font-size="10" font-weight="bold" fill="#000000">Fructose-6-P + ATP</text>
  <text x="180" y="76" font-family="Arial" font-size="9" fill="#000000">(substrates)</text>
  <line x1="240" y1="80" x2="240" y2="140" stroke="#000000" stroke-width="3.5"/>
  <polygon points="236,138 240,148 244,138" fill="#000000"/>

  <!-- Product (bottom) -->
  <rect x="164" y="290" width="152" height="34" rx="6" fill="none" stroke="#000000" stroke-width="4"/>
  <text x="168" y="308" font-family="Arial" font-size="10" font-weight="bold" fill="#000000">Fructose-1,6-bisP + ADP</text>
  <text x="194" y="320" font-family="Arial" font-size="9" fill="#000000">(product)</text>
  <line x1="240" y1="260" x2="240" y2="290" stroke="#000000" stroke-width="3.5"/>
  <polygon points="236,288 240,298 244,288" fill="#000000"/>

  <!-- ACTIVATORS (left) -->
  <text x="14" y="104" font-family="Arial" font-size="11" font-weight="bold" fill="#000000">ACTIVATORS ▶</text>

  <!-- AMP activator -->
  <rect x="14" y="110" width="100" height="28" rx="5" fill="none" stroke="#000000" stroke-width="3.5"/>
  <text x="18" y="126" font-family="Arial" font-size="10" font-weight="bold" fill="#000000">AMP ↑</text>
  <text x="18" y="138" font-family="Arial" font-size="8.5" fill="#000000">(low energy)</text>
  <line x1="114" y1="124" x2="150" y2="180" stroke="#000000" stroke-width="3.5"/>
  <polygon points="147,177 153,188 158,177" fill="#000000"/>

  <!-- ADP activator -->
  <rect x="14" y="148" width="100" height="28" rx="5" fill="none" stroke="#000000" stroke-width="3.5"/>
  <text x="18" y="164" font-family="Arial" font-size="10" font-weight="bold" fill="#000000">ADP ↑</text>
  <text x="18" y="176" font-family="Arial" font-size="8.5" fill="#000000">(moderate)</text>
  <line x1="114" y1="162" x2="150" y2="190" stroke="#000000" stroke-width="3.5"/>
  <polygon points="147,188 153,198 158,188" fill="#000000"/>

  <!-- Fructose-2,6-bisP activator -->
  <rect x="14" y="186" width="100" height="28" rx="5" fill="none" stroke="#000000" stroke-width="3.5"/>
  <text x="18" y="202" font-family="Arial" font-size="9" font-weight="bold" fill="#000000">F-2,6-bisP</text>
  <text x="16" y="212" font-family="Arial" font-size="8.5" fill="#000000">(insulin signal)</text>
  <line x1="114" y1="200" x2="150" y2="200" stroke="#000000" stroke-width="3.5"/>
  <polygon points="146,196 156,200 146,204" fill="#000000"/>

  <!-- Pi activator -->
  <rect x="14" y="224" width="100" height="28" rx="5" fill="none" stroke="#000000" stroke-width="3.5"/>
  <text x="18" y="240" font-family="Arial" font-size="10" font-weight="bold" fill="#000000">Pi ↑</text>
  <text x="18" y="252" font-family="Arial" font-size="8.5" fill="#000000">(active energy use)</text>
  <line x1="114" y1="238" x2="150" y2="218" stroke="#000000" stroke-width="3.5"/>
  <polygon points="151,220 155,208 160,218" fill="#000000"/>

  <!-- INHIBITORS (right) -->
  <text x="366" y="104" font-family="Arial" font-size="11" font-weight="bold" fill="#000000">◀ INHIBITORS</text>

  <!-- ATP inhibitor -->
  <rect x="366" y="110" width="100" height="28" rx="5" fill="none" stroke="#000000" stroke-width="3.5"/>
  <text x="370" y="126" font-family="Arial" font-size="10" font-weight="bold" fill="#000000">ATP ↑</text>
  <text x="370" y="138" font-family="Arial" font-size="8.5" fill="#000000">(high energy, allost.)</text>
  <line x1="330" y1="124" x2="366" y2="118" stroke="#000000" stroke-width="3.5"/>
  <line x1="330" y1="124" x2="330" y2="124" stroke="#000000" stroke-width="4"/>
  <!-- flat-head inhibition -->
  <line x1="330" y1="120" x2="330" y2="130" stroke="#000000" stroke-width="5"/>

  <!-- Citrate inhibitor -->
  <rect x="366" y="148" width="100" height="28" rx="5" fill="none" stroke="#000000" stroke-width="3.5"/>
  <text x="370" y="164" font-family="Arial" font-size="10" font-weight="bold" fill="#000000">Citrate ↑</text>
  <text x="370" y="176" font-family="Arial" font-size="8.5" fill="#000000">(Krebs full, FA avail)</text>
  <line x1="330" y1="162" x2="366" y2="158" stroke="#000000" stroke-width="3.5"/>
  <line x1="330" y1="158" x2="330" y2="168" stroke="#000000" stroke-width="5"/>

  <!-- H+ inhibitor -->
  <rect x="366" y="186" width="100" height="28" rx="5" fill="none" stroke="#000000" stroke-width="3.5"/>
  <text x="370" y="202" font-family="Arial" font-size="10" font-weight="bold" fill="#000000">H⁺ ↑ (low pH)</text>
  <text x="370" y="214" font-family="Arial" font-size="8.5" fill="#000000">(lactic acidosis)</text>
  <line x1="330" y1="200" x2="366" y2="200" stroke="#000000" stroke-width="3.5"/>
  <line x1="330" y1="196" x2="330" y2="206" stroke="#000000" stroke-width="5"/>

  <!-- F-2,6-bisP regulation by PFK-2 -->
  <rect x="14" y="300" width="200" height="66" rx="5" fill="none" stroke="#000000" stroke-width="3" stroke-dasharray="5,3"/>
  <text x="18" y="316" font-family="Arial" font-size="9" font-weight="bold" fill="#000000">PFK-2/FBPase-2 bifunctional:</text>
  <text x="18" y="328" font-family="Arial" font-size="8.5" fill="#000000">Insulin → Akt → PFK-2 active</text>
  <text x="18" y="340" font-family="Arial" font-size="8.5" fill="#000000">→ ↑F-2,6-bisP → ↑PFK-1</text>
  <text x="18" y="352" font-family="Arial" font-size="8.5" fill="#000000">Glucagon → PKA → FBPase-2 active</text>
  <text x="18" y="364" font-family="Arial" font-size="8.5" fill="#000000">→ ↓F-2,6-bisP → ↓PFK-1 (liver)</text>

  <!-- Sigmoidal kinetics note -->
  <rect x="270" y="300" width="196" height="66" rx="5" fill="none" stroke="#000000" stroke-width="3" stroke-dasharray="5,3"/>
  <text x="274" y="316" font-family="Arial" font-size="9" font-weight="bold" fill="#000000">Kinetics (allosteric enzyme):</text>
  <text x="274" y="328" font-family="Arial" font-size="8.5" fill="#000000">Sigmoidal V vs [S] (not hyperbolic)</text>
  <text x="274" y="340" font-family="Arial" font-size="8.5" fill="#000000">Hill coefficient n &gt; 1 (cooperative)</text>
  <text x="274" y="352" font-family="Arial" font-size="8.5" fill="#000000">AMP shifts curve left (sensitises)</text>
  <text x="274" y="364" font-family="Arial" font-size="8.5" fill="#000000">ATP shifts curve right (desensitises)</text>
</svg>`;

