// ─── 18. RUBP REGENERATION CARBON SHUFFLE ──────────────────────────────────
static rubpRegenerationCarbonShufflePhosphoribulokinaseStepDiagramsvg = `<?xml version="1.0" encoding="utf-8"?>
<svg fill="#000000" version="1.1" id="RuBPregen" xmlns="http://www.w3.org/2000/svg" xmlns:xlink="http://www.w3.org/1999/xlink"
     width="800px" height="800px" viewBox="0 0 480 420" enable-background="new 0 0 480 420" xml:space="preserve">

  <!-- Title -->
  <text x="40" y="22" font-family="Arial" font-size="12" font-weight="bold" fill="#000000">RuBP Regeneration — Carbon Shuffle &amp; PRK Step</text>
  <text x="60" y="36" font-family="Arial" font-size="9" fill="#000000">5 × G3P (C3) → 3 × RuBP (C5) using 3 ATP</text>

  <!-- Input: 5 G3P molecules (C3 each = 15C total) -->
  <text x="30" y="58" font-family="Arial" font-size="10" font-weight="bold" fill="#000000">INPUT: 5 × G3P (3C each = 15C)</text>
  <!-- G3P boxes -->
  <rect x="24" y="64" width="44" height="20" rx="3" fill="none" stroke="#000000" stroke-width="3"/>
  <text x="29" y="79" font-family="Arial" font-size="9" fill="#000000">G3P(3)</text>
  <rect x="74" y="64" width="44" height="20" rx="3" fill="none" stroke="#000000" stroke-width="3"/>
  <text x="79" y="79" font-family="Arial" font-size="9" fill="#000000">G3P(3)</text>
  <rect x="124" y="64" width="44" height="20" rx="3" fill="none" stroke="#000000" stroke-width="3"/>
  <text x="129" y="79" font-family="Arial" font-size="9" fill="#000000">G3P(3)</text>
  <rect x="174" y="64" width="44" height="20" rx="3" fill="none" stroke="#000000" stroke-width="3"/>
  <text x="179" y="79" font-family="Arial" font-size="9" fill="#000000">G3P(3)</text>
  <rect x="224" y="64" width="44" height="20" rx="3" fill="none" stroke="#000000" stroke-width="3"/>
  <text x="229" y="79" font-family="Arial" font-size="9" fill="#000000">G3P(3)</text>

  <!-- Carbon-shuffling reactions box (centre) -->
  <rect x="30" y="104" width="380" height="150" rx="6" fill="none" stroke="#000000" stroke-width="4"/>
  <text x="120" y="122" font-family="Arial" font-size="11" font-weight="bold" fill="#000000">Carbon Shuffle (Transketolase / Aldolase)</text>

  <!-- Reactions in shuffle -->
  <!-- TK reaction 1: C3 + C3 → C6 (then aldolase → C5 + C1, but simplified) -->
  <!-- Step A: Transaldolase/Aldolase reactions -->
  <rect x="44" y="130" width="110" height="24" rx="3" fill="none" stroke="#000000" stroke-width="2.5"/>
  <text x="48" y="146" font-family="Arial" font-size="8.5" fill="#000000">Aldolase: C3+C3 → F1,6BP (C6)</text>
  <line x1="154" y1="142" x2="172" y2="142" stroke="#000000" stroke-width="2.5"/>
  <polygon points="170,138 180,142 170,146" fill="#000000"/>
  <rect x="172" y="130" width="110" height="24" rx="3" fill="none" stroke="#000000" stroke-width="2.5"/>
  <text x="176" y="146" font-family="Arial" font-size="8.5" fill="#000000">Phosphatase → F6P (C6)</text>

  <!-- Step B -->
  <rect x="44" y="162" width="130" height="24" rx="3" fill="none" stroke="#000000" stroke-width="2.5"/>
  <text x="48" y="178" font-family="Arial" font-size="8.5" fill="#000000">Transketolase: F6P(C6)+C3 → C4+C5</text>
  <line x1="174" y1="174" x2="190" y2="174" stroke="#000000" stroke-width="2.5"/>
  <polygon points="188,170 198,174 188,178" fill="#000000"/>
  <rect x="190" y="162" width="96" height="24" rx="3" fill="none" stroke="#000000" stroke-width="2.5"/>
  <text x="194" y="178" font-family="Arial" font-size="8.5" fill="#000000">Xu5P(C5) + E4P(C4)</text>

  <!-- Step C -->
  <rect x="44" y="196" width="130" height="24" rx="3" fill="none" stroke="#000000" stroke-width="2.5"/>
  <text x="48" y="212" font-family="Arial" font-size="8.5" fill="#000000">Aldolase: E4P(C4)+C3 → SBP(C7)</text>
  <line x1="174" y1="208" x2="190" y2="208" stroke="#000000" stroke-width="2.5"/>
  <polygon points="188,204 198,208 188,212" fill="#000000"/>
  <rect x="190" y="196" width="130" height="24" rx="3" fill="none" stroke="#000000" stroke-width="2.5"/>
  <text x="194" y="212" font-family="Arial" font-size="8.5" fill="#000000">Transketolase: SBP(C7)+C3 → 2×C5</text>

  <!-- Step D: intermediates total to Ru5P -->
  <rect x="44" y="228" width="170" height="20" rx="3" fill="none" stroke="#000000" stroke-width="2.5"/>
  <text x="48" y="242" font-family="Arial" font-size="8.5" fill="#000000">Isomerase/Epimerase: → 3×Ru5P (C5)</text>

  <!-- Arrows from G3P inputs into shuffle box -->
  <line x1="46" y1="84" x2="96" y2="104" stroke="#000000" stroke-width="2.5"/>
  <line x1="96" y1="84" x2="96" y2="104" stroke="#000000" stroke-width="2.5"/>
  <line x1="146" y1="84" x2="140" y2="104" stroke="#000000" stroke-width="2.5"/>
  <line x1="196" y1="84" x2="200" y2="104" stroke="#000000" stroke-width="2.5"/>
  <line x1="246" y1="84" x2="230" y2="104" stroke="#000000" stroke-width="2.5"/>

  <!-- Arrow out of shuffle to PRK -->
  <line x1="220" y1="254" x2="220" y2="284" stroke="#000000" stroke-width="4"/>
  <polygon points="216,281 220,294 224,281" fill="#000000"/>
  <text x="228" y="268" font-family="Arial" font-size="9.5" font-weight="bold" fill="#000000">3 × Ru5P (C5)</text>

  <!-- PRK box -->
  <rect x="140" y="294" width="160" height="40" rx="5" fill="none" stroke="#000000" stroke-width="4.5"/>
  <text x="148" y="310" font-family="Arial" font-size="10" font-weight="bold" fill="#000000">PRK (phosphoribulokinase)</text>
  <text x="156" y="326" font-family="Arial" font-size="9" fill="#000000">Ru5P + ATP → RuBP + ADP</text>

  <!-- ATP input -->
  <line x1="100" y1="314" x2="140" y2="314" stroke="#000000" stroke-width="3" stroke-dasharray="5,3"/>
  <polygon points="136,310 148,314 136,318" fill="#000000"/>
  <text x="54" y="310" font-family="Arial" font-size="10" font-weight="bold" fill="#000000">3 ATP</text>
  <text x="56" y="322" font-family="Arial" font-size="8.5" fill="#000000">(×1 per Ru5P)</text>

  <!-- ADP output -->
  <line x1="300" y1="314" x2="336" y2="314" stroke="#000000" stroke-width="2.5" stroke-dasharray="4,3"/>
  <text x="338" y="318" font-family="Arial" font-size="10" fill="#000000">3 ADP</text>

  <!-- Arrow to RuBP -->
  <line x1="220" y1="334" x2="220" y2="364" stroke="#000000" stroke-width="4"/>
  <polygon points="216,361 220,374 224,361" fill="#000000"/>

  <!-- RuBP output boxes -->
  <text x="146" y="380" font-family="Arial" font-size="10" font-weight="bold" fill="#000000">OUTPUT: 3 × RuBP (C5 each = 15C)</text>
  <rect x="152" y="384" width="52" height="20" rx="3" fill="none" stroke="#000000" stroke-width="3.5"/>
  <text x="156" y="399" font-family="Arial" font-size="9" fill="#000000">RuBP(5)</text>
  <rect x="210" y="384" width="52" height="20" rx="3" fill="none" stroke="#000000" stroke-width="3.5"/>
  <text x="214" y="399" font-family="Arial" font-size="9" fill="#000000">RuBP(5)</text>
  <rect x="268" y="384" width="52" height="20" rx="3" fill="none" stroke="#000000" stroke-width="3.5"/>
  <text x="272" y="399" font-family="Arial" font-size="9" fill="#000000">RuBP(5)</text>

  <!-- PRK regulation note -->
  <rect x="30" y="406" width="280" height="12" rx="3" fill="none" stroke="#000000" stroke-width="1.5" stroke-dasharray="3,2"/>
  <text x="34" y="416" font-family="Arial" font-size="8" fill="#000000">PRK activated by thioredoxin (light) · inhibited by AMP / NADPH</text>
</svg>`;

