  static protistSuperGroupCladogramSARArchaeplastidaExcavataDiagramsvg = `<?xml version="1.0" encoding="utf-8"?>
<svg fill="#000000" version="1.1" xmlns="http://www.w3.org/2000/svg"
     width="800px" height="800px" viewBox="0 0 500 460" enable-background="new 0 0 500 460" xml:space="preserve">

  <!-- Title -->
  <text x="60" y="20" font-family="Arial" font-size="13" font-weight="bold" fill="#000000">Eukaryote Supergroup Cladogram</text>
  <text x="68" y="35" font-family="Arial" font-size="9" fill="#000000">SAR · Archaeplastida · Excavata · Amoebozoa · Opisthokonta</text>

  <!-- Root branch -->
  <line x1="30" y1="240" x2="80" y2="240" stroke="#000000" stroke-width="4.5"/>
  <text x="6" y="244" font-family="Arial" font-size="8.5" font-weight="bold" fill="#000000">LECA</text>

  <!-- Main split at x=80: upper (Archaeplastida+SAR+Excavata) vs lower (Amoebozoa+Opisthokonta) -->
  <line x1="80" y1="150" x2="80" y2="330" stroke="#000000" stroke-width="4.5"/>

  <!-- Upper clade line -->
  <line x1="80" y1="150" x2="130" y2="150" stroke="#000000" stroke-width="4"/>
  <!-- Lower clade line -->
  <line x1="80" y1="330" x2="130" y2="330" stroke="#000000" stroke-width="4"/>

  <!-- Upper clade splits at x=130 into Archaeplastida (top) and SAR+Excavata -->
  <line x1="130" y1="90" x2="130" y2="210" stroke="#000000" stroke-width="4"/>
  <line x1="130" y1="90" x2="190" y2="90" stroke="#000000" stroke-width="4"/>
  <!-- SAR+Excavata splits at x=130, y=210 -->
  <line x1="130" y1="210" x2="190" y2="210" stroke="#000000" stroke-width="4"/>

  <!-- SAR splits at x=190 into SAR (y=180) and Excavata (y=240) -->
  <line x1="190" y1="170" x2="190" y2="250" stroke="#000000" stroke-width="4"/>
  <line x1="190" y1="170" x2="250" y2="170" stroke="#000000" stroke-width="4"/>
  <line x1="190" y1="250" x2="250" y2="250" stroke="#000000" stroke-width="4"/>

  <!-- SAR internal: Stramenopiles / Alveolata / Rhizaria -->
  <line x1="250" y1="140" x2="250" y2="200" stroke="#000000" stroke-width="3.5"/>
  <line x1="250" y1="140" x2="320" y2="140" stroke="#000000" stroke-width="3.5"/>
  <line x1="250" y1="170" x2="320" y2="170" stroke="#000000" stroke-width="3.5"/>
  <line x1="250" y1="200" x2="320" y2="200" stroke="#000000" stroke-width="3.5"/>

  <!-- Leaf labels -->
  <!-- Archaeplastida -->
  <rect x="190" y="78" width="120" height="24" rx="4" fill="none" stroke="#000000" stroke-width="3"/>
  <text x="194" y="95" font-family="Arial" font-size="9" font-weight="bold" fill="#000000">Archaeplastida</text>
  <!-- red/green algae internal -->
  <line x1="310" y1="90" x2="380" y2="72" stroke="#000000" stroke-width="2.5"/>
  <line x1="310" y1="90" x2="380" y2="90" stroke="#000000" stroke-width="2.5"/>
  <line x1="310" y1="90" x2="380" y2="108" stroke="#000000" stroke-width="2.5"/>
  <text x="382" y="76" font-family="Arial" font-size="8" fill="#000000">Red algae</text>
  <text x="382" y="94" font-family="Arial" font-size="8" fill="#000000">Green algae</text>
  <text x="382" y="112" font-family="Arial" font-size="8" fill="#000000">Land plants</text>

  <!-- Stramenopiles -->
  <text x="322" y="144" font-family="Arial" font-size="8.5" font-weight="bold" fill="#000000">Stramenopiles</text>
  <text x="324" y="155" font-family="Arial" font-size="7.5" fill="#000000">Diatoms, brown algae, oomycetes</text>
  <!-- Alveolata -->
  <text x="322" y="174" font-family="Arial" font-size="8.5" font-weight="bold" fill="#000000">Alveolata</text>
  <text x="324" y="185" font-family="Arial" font-size="7.5" fill="#000000">Ciliates, dinoflagellates, apicomplexa</text>
  <!-- Rhizaria -->
  <text x="322" y="204" font-family="Arial" font-size="8.5" font-weight="bold" fill="#000000">Rhizaria</text>
  <text x="324" y="215" font-family="Arial" font-size="7.5" fill="#000000">Foraminifera, radiolaria</text>

  <!-- Excavata -->
  <rect x="252" y="238" width="100" height="24" rx="4" fill="none" stroke="#000000" stroke-width="3"/>
  <text x="256" y="254" font-family="Arial" font-size="9" font-weight="bold" fill="#000000">Excavata</text>
  <text x="360" y="252" font-family="Arial" font-size="7.5" fill="#000000">Giardia, Euglena, Trypanosoma</text>

  <!-- Lower clade: Amoebozoa + Opisthokonta split -->
  <line x1="130" y1="290" x2="130" y2="370" stroke="#000000" stroke-width="4"/>
  <line x1="130" y1="290" x2="200" y2="290" stroke="#000000" stroke-width="4"/>
  <line x1="130" y1="370" x2="200" y2="370" stroke="#000000" stroke-width="4"/>

  <!-- Amoebozoa -->
  <rect x="200" y="278" width="100" height="24" rx="4" fill="none" stroke="#000000" stroke-width="3"/>
  <text x="204" y="294" font-family="Arial" font-size="9" font-weight="bold" fill="#000000">Amoebozoa</text>
  <text x="308" y="293" font-family="Arial" font-size="7.5" fill="#000000">Amoeba, Dictyostelium, Entamoeba</text>

  <!-- Opisthokonta splits into Fungi and Animalia -->
  <line x1="200" y1="350" x2="200" y2="390" stroke="#000000" stroke-width="4"/>
  <line x1="200" y1="350" x2="260" y2="350" stroke="#000000" stroke-width="4"/>
  <line x1="200" y1="390" x2="260" y2="390" stroke="#000000" stroke-width="4"/>
  <text x="262" y="330" font-family="Arial" font-size="8.5" font-weight="bold" fill="#000000">Opisthokonta</text>
  <text x="262" y="354" font-family="Arial" font-size="8.5" font-weight="bold" fill="#000000">Fungi</text>
  <text x="306" y="354" font-family="Arial" font-size="7.5" fill="#000000">Mushrooms, yeasts, moulds</text>
  <text x="262" y="394" font-family="Arial" font-size="8.5" font-weight="bold" fill="#000000">Animalia</text>
  <text x="306" y="394" font-family="Arial" font-size="7.5" fill="#000000">Choanoflagellate sister group</text>

  <!-- Synapomorphy annotations -->
  <!-- Primary plastid -->
  <line x1="155" y1="90" x2="155" y2="82" stroke="#000000" stroke-width="2.5"/>
  <circle cx="155" cy="90" r="5" fill="none" stroke="#000000" stroke-width="2.5"/>
  <text x="130" y="78" font-family="Arial" font-size="7" font-style="italic" fill="#000000">primary plastid</text>

  <!-- Posterior flagellum -->
  <line x1="165" y1="370" x2="165" y2="362" stroke="#000000" stroke-width="2.5"/>
  <circle cx="165" cy="370" r="5" fill="none" stroke="#000000" stroke-width="2.5"/>
  <text x="118" y="358" font-family="Arial" font-size="7" font-style="italic" fill="#000000">posterior flagellum</text>

  <!-- Legend note -->
  <text x="20" y="430" font-family="Arial" font-size="8.5" fill="#000000">● = synapomorphy (shared derived character state)</text>
  <text x="20" y="444" font-family="Arial" font-size="8" fill="#000000">Protists = paraphyletic — all non-plant/non-fungal/non-animal eukaryotes</text>
</svg>`;

