  // ─── 9. CATABOLIC / ANABOLIC ENERGY FLOW ─────────────────────────────────
  static catabolicAnabolicEnergyFlowDiagramsvg = `<?xml version="1.0" encoding="utf-8"?>
<svg fill="#000000" version="1.1" id="CatAna" xmlns="http://www.w3.org/2000/svg" xmlns:xlink="http://www.w3.org/1999/xlink"
     width="800px" height="800px" viewBox="0 0 400 440" enable-background="new 0 0 400 440" xml:space="preserve">

  <text x="72" y="22" font-family="Arial" font-size="13" font-weight="bold" fill="#000000">Catabolic vs Anabolic Energy Flow</text>

  <!-- Central ATP/ADP cycle hub -->
  <ellipse cx="200" cy="220" rx="52" ry="36" fill="none" stroke="#000000" stroke-width="5"/>
  <text x="172" y="214" font-family="Arial" font-size="11" font-weight="bold" fill="#000000">ATP / ADP</text>
  <text x="178" y="228" font-family="Arial" font-size="10" fill="#000000">Energy</text>
  <text x="180" y="240" font-family="Arial" font-size="10" fill="#000000">Currency</text>

  <!-- ── CATABOLISM side (left) ── -->
  <rect x="14" y="80" width="120" height="60" rx="6" fill="none" stroke="#000000" stroke-width="4.5"/>
  <text x="24" y="102" font-family="Arial" font-size="10" font-weight="bold" fill="#000000">Complex</text>
  <text x="28" y="114" font-family="Arial" font-size="10" font-weight="bold" fill="#000000">Molecules</text>
  <text x="20" y="128" font-family="Arial" font-size="8.5" fill="#000000">Glucose, Fats, Proteins</text>

  <!-- Arrow complex → ATP (catabolism) -->
  <path d="M74,140 C74,165 120,185 148,205" fill="none" stroke="#000000" stroke-width="4"/>
  <polygon points="143,204 152,214 157,203" fill="#000000"/>
  <!-- Label on arrow -->
  <text x="60" y="176" font-family="Arial" font-size="9" font-weight="bold" fill="#000000">CATABOLISM</text>
  <text x="52" y="188" font-family="Arial" font-size="8" fill="#000000">Breakdown → ATP</text>
  <!-- Small molecule products box -->
  <rect x="14" y="290" width="120" height="56" rx="6" fill="none" stroke="#000000" stroke-width="3.5" stroke-dasharray="6,3"/>
  <text x="26" y="312" font-family="Arial" font-size="9" font-weight="bold" fill="#000000">Small Products</text>
  <text x="20" y="326" font-family="Arial" font-size="8" fill="#000000">CO₂, H₂O, NH₃</text>
  <text x="22" y="338" font-family="Arial" font-size="8" fill="#000000">Heat released</text>
  <!-- Arrow catabolism → small products -->
  <line x1="74" y1="140" x2="74" y2="290" stroke="#000000" stroke-width="3" stroke-dasharray="5,3"/>
  <polygon points="70,287 74,299 78,287" fill="#000000"/>

  <!-- ── ANABOLISM side (right) ── -->
  <rect x="266" y="80" width="120" height="60" rx="6" fill="none" stroke="#000000" stroke-width="4.5"/>
  <text x="286" y="102" font-family="Arial" font-size="10" font-weight="bold" fill="#000000">Complex</text>
  <text x="290" y="114" font-family="Arial" font-size="10" font-weight="bold" fill="#000000">Products</text>
  <text x="272" y="128" font-family="Arial" font-size="8.5" fill="#000000">Proteins, DNA, Glycogen</text>

  <!-- Arrow ATP → complex products (anabolism) -->
  <path d="M252,205 C270,188 300,162 326,140" fill="none" stroke="#000000" stroke-width="4"/>
  <polygon points="321,138 330,131 328,143" fill="#000000"/>
  <text x="274" y="176" font-family="Arial" font-size="9" font-weight="bold" fill="#000000">ANABOLISM</text>
  <text x="268" y="188" font-family="Arial" font-size="8" fill="#000000">ATP → Biosynthesis</text>

  <!-- Small precursors box -->
  <rect x="266" y="290" width="120" height="56" rx="6" fill="none" stroke="#000000" stroke-width="3.5" stroke-dasharray="6,3"/>
  <text x="278" y="312" font-family="Arial" font-size="9" font-weight="bold" fill="#000000">Precursors</text>
  <text x="270" y="326" font-family="Arial" font-size="8" fill="#000000">Amino acids, sugars</text>
  <text x="274" y="338" font-family="Arial" font-size="8" fill="#000000">nucleotides, FA</text>
  <!-- Arrow precursors → anabolism -->
  <line x1="326" y1="290" x2="326" y2="140" stroke="#000000" stroke-width="3" stroke-dasharray="5,3"/>
  <polygon points="322,143 326,131 330,143" fill="#000000"/>

  <!-- ATP cycle arrows around hub -->
  <!-- ATP releases energy down (→ ADP + Pi) -->
  <path d="M200,256 C200,280 200,300 200,318" fill="none" stroke="#000000" stroke-width="3.5"/>
  <polygon points="196,315 200,328 204,315" fill="#000000"/>
  <text x="206" y="296" font-family="Arial" font-size="8.5" font-weight="bold" fill="#000000">ATP → ADP+Pi</text>
  <text x="208" y="307" font-family="Arial" font-size="8" fill="#000000">Energy released</text>

  <!-- ADP recharged (← ADP + Pi → ATP) -->
  <path d="M200,184 C200,160 200,140 200,118" fill="none" stroke="#000000" stroke-width="3.5"/>
  <polygon points="196,121 200,108 204,121" fill="#000000"/>
  <text x="206" y="164" font-family="Arial" font-size="8.5" font-weight="bold" fill="#000000">ADP+Pi → ATP</text>
  <text x="208" y="175" font-family="Arial" font-size="8" fill="#000000">Energy stored</text>

  <!-- Energy use box bottom -->
  <rect x="128" y="328" width="144" height="46" rx="5" fill="none" stroke="#000000" stroke-width="3"/>
  <text x="136" y="346" font-family="Arial" font-size="8.5" font-weight="bold" fill="#000000">ATP Energy Uses:</text>
  <text x="134" y="358" font-family="Arial" font-size="8" fill="#000000">Movement · Synthesis</text>
  <text x="134" y="369" font-family="Arial" font-size="8" fill="#000000">Transport · Signalling</text>

  <!-- NADH/FADH2 label on catabolic arrow -->
  <rect x="10" y="200" width="84" height="32" rx="3" fill="none" stroke="#000000" stroke-width="2" stroke-dasharray="4,3"/>
  <text x="14" y="213" font-family="Arial" font-size="8" font-weight="bold" fill="#000000">Electron carriers:</text>
  <text x="14" y="225" font-family="Arial" font-size="8" fill="#000000">NADH, FADH₂</text>

  <!-- NADPH label on anabolic side -->
  <rect x="306" y="200" width="84" height="32" rx="3" fill="none" stroke="#000000" stroke-width="2" stroke-dasharray="4,3"/>
  <text x="310" y="213" font-family="Arial" font-size="8" font-weight="bold" fill="#000000">Reducing power:</text>
  <text x="314" y="225" font-family="Arial" font-size="8" fill="#000000">NADPH</text>

  <!-- Title labels for sides -->
  <text x="16" y="62" font-family="Arial" font-size="11" font-weight="bold" fill="#000000">▼ CATABOLISM</text>
  <text x="14" y="74" font-family="Arial" font-size="8.5" fill="#000000">Exergonic · Oxidative · ΔG &lt; 0</text>
  <text x="266" y="62" font-family="Arial" font-size="11" font-weight="bold" fill="#000000">▲ ANABOLISM</text>
  <text x="268" y="74" font-family="Arial" font-size="8.5" fill="#000000">Endergonic · Reductive · ΔG &gt; 0</text>
</svg>`;

